where.trim:
AND a.store_id = #{storeId}
AND a.is_delete = 0
AND c.`status` IS NOT NULL
AND a.is_refund = 0
AND f.sell_type = #{sellType}
AND c.status = #{status}
AND(f.product_title like CONCAT('%', #{titleOrId},'%') or
  f.product_id = #{titleOrId})

AND f.product_title like CONCAT('%', #{productTitle},'%')
and m.name like concat('%',#{mchName},'%')
AND m.id = #{mchId}
AND f.product_id = #{productId}
AND c.add_time   >=   #{startTime}
AND c.add_time   <=   #{endTime}
AND (a.sNo like CONCAT('%', #{condition},'%') or b.user_name like CONCAT('%', #{condition},'%') or b.mobile = #{condition} or b.user_id = #{condition})

  
    #{status,jdbcType=INTEGER}
  

and c.store_recycle = #{storeRecycle}
and c.mch_recycle = #{mchRecycle}

mapper.sql:
    and o.store_id = #{store_id}
    and p.sell_type = #{sell_type}
    and o.recycle != #{recycle}
    and o.otype = #{orderType}
    and o.status = #{orderStauts}
    and o.mch_id like CONCAT('%,',#{mch_id},',%')
    and o.add_time   >=   #{startDay}
    and o.add_time   <=   #{endDay}
    and o.otype != #{notOtype}
    and o.`status` != 7
    and o.`status` != #{notStatusType}
    and date_add(o.add_time, interval IFNULL(order_failure_time, #{orderFailureTime})
      second)   <   #{sysDate}
